CREATE TABLE IF NOT EXISTS "users" (
  "id" bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "username" character varying NOT NULL,
  "display" character varying NOT NULL,
  "password_hash" character varying NULL,
  "must_change_password" boolean NOT NULL DEFAULT false,
  "password_changed_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
CREATE UNIQUE INDEX IF NOT EXISTS "users_username_key" ON "users" ("username");

CREATE TABLE IF NOT EXISTS "refresh_sessions" (
  "id" bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "token_id" character varying NOT NULL,
  "expires_at" timestamptz NOT NULL,
  "revoked_at" timestamptz NULL,
  "replaced_by_token_id" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "user_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "refresh_sessions_users_refresh_sessions"
    FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE UNIQUE INDEX IF NOT EXISTS "refresh_sessions_token_id_key" ON "refresh_sessions" ("token_id");
CREATE INDEX IF NOT EXISTS "refreshsession_user_id" ON "refresh_sessions" ("user_id");
CREATE INDEX IF NOT EXISTS "refreshsession_expires_at" ON "refresh_sessions" ("expires_at");
